//axhob_operation
{bust_handbook_jurisdiction_top}

NOTE: Top-level landing surface for the {bus_jurisdiction} handbook.
Renders handbook prose to the operator's terminal as the entry point
into bootstrap, garrison, and dispatch procedures.
No remote contact and no profile mutation.

//axhos_step
. *Render landing*: emit the jurisdiction handbook landing content,
including pointers to the admin SSH bootstrap procedure (operator-
manual prerequisite to {busn_garrison}), the per-shell-letter
garrison tabtargets, and the workload dispatch tabtargets.

//axhog_guarantee
No remote contact occurred and no local file was written.

//axhoc_completion
Exit 0 after the landing content is printed.
Non-zero only when the handbook content cannot be located or rendered.

= Bash Utilities Specification
:doctype: book

// tag::mapping-section[]
//
// Category declarations:
// bust_:  Tabtarget (launcher naming vesture)
// busd:   Dispatch (non-terminal, tabtarget system umbrella)
// busdc_: Dispatch Colophon (routing identifier)
// busdf_: Dispatch Frontispiece (human-readable description)
// busdi_: Dispatch Imprint (embedded parameter/target specifier)
// busdm_: Dispatch Formulary (routing component)
// busdl_: Dispatch Launcher (bootstrap script)
// bukro_: Kit Regime Operation (kindle/validate/render)
// burc_:  Configuration Regime (project-level settings)
// burn_:  Node Regime (per-node SSH connection profiles, multi-instance)
// burs_:  Station Regime (developer-level settings)
// burd_:  Dispatch Runtime (ephemeral state assembled during dispatch)
// bure_:  Environment Regime (ambient caller-supplied behavioral overrides)
// busi:   Invocation (test invocation umbrella)
// busn_:  Node Access (verbs for remote node management)
// busit_: Invocation Tier (tier classification)
// busig_: Invocation Global (capture state set by zbuto_invoke)
// busx_:  Case Boundary (test case isolation runner)
// busff_: Fact-File (inter-step communication via output files)
// buf_:   Fact Module (dual-write fact-file primitives)
// busy_:  Yelp (pre-rendered formatted string capture)
// burx_:  Exchange Regime (cross-project dispatch state)
// bus_:   Specification umbrella concept (e.g., bus_jurisdiction)
// bujb_:  Jurisdiction implementation seat — sub-letter `b` = bash format.
//         Future PowerShell sibling would mint as bujp_; under Quoin
//         Sub-Letter Discipline, sub-letter Y is monosemic per domain
//         (b → bash, p → powershell — never reused for other concepts
//         within the buj* tree).
//
// Variant patterns:
//   _s: plural form
//   _p: possessive form
//

// Tabtarget Vesture
:bust_tabtarget:        <<bust_tabtarget,Tabtarget Vesture>>

// Jurisdiction Tabtargets
:bust_fenestrate:                  <<bust_fenestrate,Fenestrate>>
:bust_privileged_ssh:              <<bust_privileged_ssh,Privileged SSH>>
:bust_garrison_bash:               <<bust_garrison_bash,Garrison Bash>>
:bust_garrison_cygwin:             <<bust_garrison_cygwin,Garrison Cygwin>>
:bust_garrison_wsl:                <<bust_garrison_wsl,Garrison WSL>>
:bust_knock:                       <<bust_knock,Knock>>
:bust_command_file:                <<bust_command_file,Command File>>
:bust_interactive_session:         <<bust_interactive_session,Interactive Session>>
:bust_handbook_jurisdiction_top:   <<bust_handbook_jurisdiction_top,Handbook Jurisdiction Top>>

// Regime Config Tabtargets
:bust_node_regime_list:            <<bust_node_regime_list,Node Regime List>>
:bust_node_regime_render:          <<bust_node_regime_render,Node Regime Render>>
:bust_node_regime_validate:        <<bust_node_regime_validate,Node Regime Validate>>
:bust_privilege_regime_list:       <<bust_privilege_regime_list,Privilege Regime List>>
:bust_privilege_regime_render:     <<bust_privilege_regime_render,Privilege Regime Render>>
:bust_privilege_regime_validate:   <<bust_privilege_regime_validate,Privilege Regime Validate>>

// Input Artifacts
:busi_scribed_command_file:  <<busi_scribed_command_file,Scribed Command File>>

// Dispatch
:busdc_colophon:        <<busdc_colophon,Colophon>>
:busdc_colophon_s:      <<busdc_colophon,Colophons>>
:busdf_frontispiece:    <<busdf_frontispiece,Frontispiece>>
:busdf_frontispiece_s:  <<busdf_frontispiece,Frontispieces>>
:busdi_imprint:         <<busdi_imprint,Imprint>>
:busdi_imprint_s:       <<busdi_imprint,Imprints>>
:busdm_formulary:       <<busdm_formulary,Formulary>>
:busdm_formulary_s:     <<busdm_formulary,Formularies>>
:busdl_launcher:        <<busdl_launcher,Launcher>>
:busdl_launcher_s:      <<busdl_launcher,Launchers>>

// Axial Regime Terms (from AXLA — matching RBSA)
:axrg_assignment:                  <<axrg_assignment,Assignment>>
:axrg_assignment_s:                <<axrg_assignment,Assignments>>
:axrg_prefix:                      <<axrg_prefix,Regime Prefix>>
:axrg_regime:                      <<axrg_regime,Regime>>
:axrg_regime_s:                    <<axrg_regime,Regimes>>
:axrg_variable:                    <<axrg_variable,Regime Variable>>
:axrg_variable_s:                  <<axrg_variable,Regime Variables>>

// Axial Format Terms (from AXLA — matching RBSA)
:axf_bash:                         <<axf_bash,Bash Format>>

// BUK Regime Operation Terms
:bukro_kindle:                     <<bukro_kindle,BUK Kindle>>
:bukro_validate:                   <<bukro_validate,BUK Validate>>
:bukro_render:                     <<bukro_render,BUK Render>>

// BUK Regime Prefixes
:burc_prefix:                      <<burc_prefix,BURC_>>
:burn_prefix:                      <<burn_prefix,BURN_>>
:burp_prefix:                      <<burp_prefix,BURP_>>
:burs_prefix:                      <<burs_prefix,BURS_>>

// BURC Regime: Configuration (project-level BUK settings)
:burc_regime:                      <<burc_regime,BURC Regime>>
:burc_station_file:                <<burc_station_file,BURC_STATION_FILE>>
:burc_tabtarget_dir:               <<burc_tabtarget_dir,BURC_TABTARGET_DIR>>
:burc_tabtarget_delimiter:         <<burc_tabtarget_delimiter,BURC_TABTARGET_DELIMITER>>
:burc_tools_dir:                   <<burc_tools_dir,BURC_TOOLS_DIR>>
:burc_project_root:                <<burc_project_root,BURC_PROJECT_ROOT>>
:burc_managed_kits:                <<burc_managed_kits,BURC_MANAGED_KITS>>
:burc_temp_root_dir:               <<burc_temp_root_dir,BURC_TEMP_ROOT_DIR>>
:burc_output_root_dir:             <<burc_output_root_dir,BURC_OUTPUT_ROOT_DIR>>
:burc_log_last:                    <<burc_log_last,BURC_LOG_LAST>>
:burc_log_ext:                     <<burc_log_ext,BURC_LOG_EXT>>

// BURN Regime: Node-shape (per-node, project-global, git-tracked)
:burn_regime:                      <<burn_regime,BURN Regime>>
:burn_host:                        <<burn_host,BURN_HOST>>
:burn_platform:                    <<burn_platform,BURN_PLATFORM>>

// BURN/BURP Identifier Vocabulary
:burn_investiture:                 <<burn_investiture,Investiture>>
:burp_investiture:                 <<burp_investiture,Investiture>>

// Cross-cutting premises for BURN/BURP
:burn_host_singularity:            <<burn_host_singularity,Host Singularity>>
:bus_keys_operator_owned:          <<bus_keys_operator_owned,Operator-Owned Keys>>

// Jurisdiction (logical umbrella + implementation seat)
:bus_jurisdiction:                 <<bus_jurisdiction,Jurisdiction>>
:bujb_jurisdiction:                <<bujb_jurisdiction,bujb_jurisdiction.sh>>
:bujb_workload_user:               <<bujb_workload_user,BUJB_workload_user>>

// BURP Regime: Privileged + Workload Credentials (per-station-user)
:burp_regime:                      <<burp_regime,BURP Regime>>
:burp_privileged_user:             <<burp_privileged_user,BURP_PRIVILEGED_USER>>
:burp_privileged_key_file:         <<burp_privileged_key_file,BURP_PRIVILEGED_KEY_FILE>>
:burp_workload_key_file:           <<burp_workload_key_file,BURP_WORKLOAD_KEY_FILE>>

// BUSN: Node Access (verbs for remote node management)
:busn_fenestrate:                  <<busn_fenestrate,Fenestrate>>
:busn_garrison:                    <<busn_garrison,Garrison>>

// BURS Regime: Station (developer-level BUK settings)
:burs_regime:                      <<burs_regime,BURS Regime>>
:burs_user:                        <<burs_user,BURS_USER>>
:burs_tincture:                    <<burs_tincture,BURS_TINCTURE>>
:burs_log_dir:                     <<burs_log_dir,BURS_LOG_DIR>>

// BURD Regime: Dispatch Runtime (ephemeral dispatch state)
:burd_regime:                      <<burd_regime,BURD Regime>>
:burd_prefix:                      <<burd_prefix,BURD_>>

// BURD Groups
:burd_group_input:                 <<burd_group_input,Input Variables>>
:burd_group_computed:              <<burd_group_computed,Computed Variables>>
:burd_group_parsed:                <<burd_group_parsed,Parsed Variables>>

// BURD Input Variables
:burd_regime_file:                 <<burd_regime_file,BURD_REGIME_FILE>>
:burd_no_log:                      <<burd_no_log,BURD_NO_LOG>>
:burd_interactive:                 <<burd_interactive,BURD_INTERACTIVE>>

